import{f as a,o as e,c as o,a2 as l}from"./chunks/framework.Ccw_j35p.js";const b=JSON.parse('{"title":"分布式理论","description":"","frontmatter":{"title":"分布式理论","outline":[2,3]},"headers":[],"relativePath":"middleware/distributed-system/index.md","filePath":"middleware/distributed-system/index.md","lastUpdated":1780747276000}'),r={name:"middleware/distributed-system/index.md"};function i(s,t,d,n,h,c){return e(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="分布式理论" tabindex="-1">分布式理论 <a class="header-anchor" href="#分布式理论" aria-label="Permalink to &quot;分布式理论&quot;">​</a></h1><blockquote><p>构建大规模互联网基础设施的基石，不仅在于&quot;能跑起来&quot;，更在于对分布式系统本质原理的深刻理解。</p></blockquote><h2 id="什么是分布式系统" tabindex="-1">什么是分布式系统 <a class="header-anchor" href="#什么是分布式系统" aria-label="Permalink to &quot;什么是分布式系统&quot;">​</a></h2><p><strong>分布式系统</strong>是指由多台独立的计算机节点通过网络互联、协同工作，对外呈现为统一整体的系统。Leslie Lamport 给出过一个经典定义：&quot;分布式系统就是这样一个系统，你甚至不知道存在一台你从未听说过的计算机的故障，就可能导致你自己的计算机无法使用。&quot;</p><p>分布式系统的核心特征：</p><ul><li><strong>多节点协作</strong>：每个节点拥有独立的 CPU、内存和存储；</li><li><strong>通过网络通信</strong>：节点之间通过不可靠的网络传递消息；</li><li><strong>无全局时钟</strong>：不存在一个统一的物理时钟来给所有事件排序；</li><li><strong>对用户透明</strong>：不论底层有多少节点，用户看到的应是一个完整的系统。</li></ul><h2 id="核心挑战" tabindex="-1">核心挑战 <a class="header-anchor" href="#核心挑战" aria-label="Permalink to &quot;核心挑战&quot;">​</a></h2><p>在分布式系统中，有八个字是绕不开的诅咒——<strong>&quot;网络不可靠、时钟不同步&quot;</strong>。</p><table tabindex="0"><thead><tr><th>挑战</th><th>具体表现</th><th>导致的后果</th></tr></thead><tbody><tr><td><strong>网络不可靠</strong></td><td>消息延迟、丢包、乱序、网络分区</td><td>节点间状态不一致，无法判断对方是宕机还是网络不通</td></tr><tr><td><strong>时钟不同步</strong></td><td>各节点物理时钟存在漂移，NTP 同步精度有限</td><td>事件顺序难以确定，依赖时间的逻辑可能出错</td></tr><tr><td><strong>节点故障</strong></td><td>进程崩溃、磁盘损坏、OOM、机器宕机</td><td>数据丢失、服务不可用、脑裂</td></tr><tr><td><strong>数据一致性</strong></td><td>多个副本之间如何保持相同的数据视图</td><td>读到旧数据、写入丢失、更新冲突</td></tr></tbody></table><h2 id="四大知识域导航" tabindex="-1">四大知识域导航 <a class="header-anchor" href="#四大知识域导航" aria-label="Permalink to &quot;四大知识域导航&quot;">​</a></h2><p>本系列文档围绕分布式系统的四大核心知识域展开：</p><h3 id="_1-cap-与-base-理论" tabindex="-1">1. CAP 与 BASE 理论 <a class="header-anchor" href="#_1-cap-与-base-理论" aria-label="Permalink to &quot;1. CAP 与 BASE 理论&quot;">​</a></h3><p><a href="./cap-base">➡️ 查看详情</a></p><p>CAP 定理是分布式系统设计的&quot;第一性原理&quot;，揭示了<strong>一致性（Consistency）、可用性（Availability）、分区容错性（Partition Tolerance）</strong> 三者之间的关系。BASE 理论则是对 CAP 中 AP 方案的工程实践补充。</p><ul><li>CAP 定理深度解析（三要素定义、CP vs AP 本质选择）</li><li>BASE 理论（BA / Soft State / Eventually Consistent）</li><li>BASE vs ACID 全面对比</li><li>分布式一致性模型详解</li><li>各主流中间件的 CAP 定位映射</li></ul><h3 id="_2-一致性协议" tabindex="-1">2. 一致性协议 <a class="header-anchor" href="#_2-一致性协议" aria-label="Permalink to &quot;2. 一致性协议&quot;">​</a></h3><p><a href="./consensus">➡️ 查看详情</a></p><p>共识（Consensus）是分布式系统最核心的问题：<strong>一组节点如何就某个共同的值或决策达成一致</strong>，即使部分节点可能出现故障。</p><ul><li>Paxos 算法（Basic Paxos 三角色模型、两阶段流程、Multi-Paxos 优化）</li><li>Raft 算法（Leader 选举、日志复制、安全性三大子问题）</li><li>ZAB 协议（ZooKeeper 原子广播协议，四模式详解）</li><li>其他协议（2PC / 3PC、Gossip 协议）</li><li>集群架构模式（主从、对等、分区与分片、故障检测）</li></ul><h3 id="_3-集群架构与中间件" tabindex="-1">3. 集群架构与中间件 <a class="header-anchor" href="#_3-集群架构与中间件" aria-label="Permalink to &quot;3. 集群架构与中间件&quot;">​</a></h3><p>集群架构是将分布式理论落地到具体中间件的实践成果。本节涵盖主流分布式中间件的核心原理：</p><table tabindex="0"><thead><tr><th>中间件</th><th>类型</th><th>核心文档</th></tr></thead><tbody><tr><td><strong>ZooKeeper</strong></td><td>分布式协调服务</td><td><a href="./zookeeper">➡️ ZooKeeper 核心</a></td></tr><tr><td><strong>Nacos</strong></td><td>服务发现与配置管理</td><td><a href="./nacos">➡️ Nacos 核心</a></td></tr><tr><td><strong>Dubbo</strong></td><td>高性能 RPC 框架</td><td><a href="./dubbo">➡️ Dubbo 核心</a></td></tr><tr><td><strong>分布式事务</strong></td><td>跨服务事务协调</td><td><a href="./transaction">➡️ 分布式事务</a></td></tr><tr><td><strong>分布式 ID</strong></td><td>全局唯一 ID 生成</td><td><a href="./id-generator">➡️ 分布式 ID</a></td></tr></tbody></table><h3 id="_4-面试高频题" tabindex="-1">4. 面试高频题 <a class="header-anchor" href="#_4-面试高频题" aria-label="Permalink to &quot;4. 面试高频题&quot;">​</a></h3><p>本文档系列包含完整的面试题解析，涵盖：</p><ul><li>CAP 为什么不能同时满足三者？</li><li>BASE 和 ACID 的区别与适用场景？</li><li>Raft 如何保证安全性？</li><li>Paxos 与 Raft 的全面对比？</li><li>什么是脑裂？如何避免？</li><li>ZooKeeper 的核心原理与一致性保证？</li><li>Nacos 的 AP/CP 双模式如何选择？</li><li>Dubbo 的服务调用全链路是怎样的？</li></ul><h2 id="推荐阅读顺序" tabindex="-1">推荐阅读顺序 <a class="header-anchor" href="#推荐阅读顺序" aria-label="Permalink to &quot;推荐阅读顺序&quot;">​</a></h2><p>对于不同背景的读者，建议按以下顺序阅读：</p><div class="tip custom-block"><p class="custom-block-title">初学者路径</p><ol><li>先阅读本页，理解分布式系统的核心挑战</li><li>阅读 <a href="./cap-base">CAP 与 BASE</a>，建立理论基础</li><li>阅读 <a href="./consensus">一致性协议</a> 了解共识算法</li><li>按需阅读具体中间件文档</li></ol></div><div class="info custom-block"><p class="custom-block-title">进阶路径</p><ol><li>快速回顾 <a href="./cap-base">CAP 与 BASE</a> 中的面试题</li><li>深入 <a href="./consensus">一致性协议</a> 的算法细节</li><li>重点研究 <a href="./zookeeper">ZooKeeper 核心</a> 的 ZAB 协议和分布式锁</li><li>结合 <a href="./nacos">Nacos 核心</a> 和 <a href="./dubbo">Dubbo 核心</a> 理解微服务架构</li></ol></div><div class="warning custom-block"><p class="custom-block-title">面试突击路径</p><ol><li>直接跳到各文档的&quot;经典高频面试题&quot;部分</li><li>重点掌握 CAP/BASE、Raft、脑裂、ZooKeeper 分布式锁、Nacos AP/CP、Dubbo 调用链</li><li>回头补充核心原理部分以加深理解</li></ol></div>',30)])])}const p=a(r,[["render",i]]);export{b as __pageData,p as default};
